import stim

# Clean up
clean_stabilizers = [s.strip() for s in raw_stabilizers.replace('\n', ' ').split(',') if s.strip()]

print(f"Count: {len(clean_stabilizers)}")

# Regenerate circuit with these EXACT stabilizers
tableau = stim.Tableau.from_stabilizers([stim.PauliString(s) for s in clean_stabilizers], allow_underconstrained=True)
circuit = tableau.to_circuit(method="graph_state")

# Replace RX with H
new_circuit = stim.Circuit()
for instr in circuit:
    if instr.name == "RX":
        new_circuit.append("H", instr.targets_copy())
    else:
        new_circuit.append(instr)

print(f"New circuit length: {len(new_circuit)}")

# Verify
sim = stim.TableauSimulator()
sim.do(new_circuit)
failed = 0
for s in clean_stabilizers:
    if sim.peek_observable_expectation(stim.PauliString(s)) != 1:
        failed += 1
print(f"Failed: {failed}")

with open("synthesized_candidate_verified.stim", "w") as f:
    f.write(str(new_circuit))
